<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#CDD6F4;"> response</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">content  </span><span style="color:#6C7086;font-style:italic;"># Final answer</span></span>
